package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;

import java.util.Collection;
import java.util.HashSet;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PRE_BEREKENING_CONTEXT_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

public class PostRekenControles extends AbstractRekenCommand {

    public PostRekenControles() {
    }

    @Override
    protected boolean execute(RekenContext context) {
        Persoon persoon = context.getUnchecked(PERSOON_KEY);
        LoonElementManager loonElementManager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RegulManager regulManager = context.getUnchecked(REGUL_MANAGER_KEY);
        RekenTijd rekenTijd = context.getUnchecked(REKENTIJD_KEY);

        RekenContext preBerekeningContext = context.getUnchecked(PRE_BEREKENING_CONTEXT_KEY);
        LoonElementManager prevLoonElementManager = preBerekeningContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Set<Opdracht> opdrachten = persoon.getOpdrachten();
        for (Opdracht opdracht : opdrachten) {
            checkRegulBelastbaarGroterDanBedrijfsvoorheffing(opdracht, loonElementManager, prevLoonElementManager, regulManager, rekenTijd);
        }

        return CONTINUE_PROCESSING;
    }

    private void checkRegulBelastbaarGroterDanBedrijfsvoorheffing(
            Opdracht opdracht, LoonElementManager loonElementManager,
            LoonElementManager prevLoonElementManager, RegulManager regulManager, RekenTijd rekenTijd) {

        if (!RekenTools.isOpdrachtBedrijfsvoorheffingVrijwilligeBrandweer(opdracht.getHoedanigheid())) {
            MoneyMap<RekenBvKey> bvKeyToBbMap = new HashMoneyMap<>();
            MoneyMap<RekenBvKey> bvKeyToBvMap = new HashMoneyMap<>();
            MoneyMap<RekenBvKey> bvKeyToBbAstMap = new HashMoneyMap<>();
            MoneyMap<RekenBvKey> bvKeyToBvAstMap = new HashMoneyMap<>();
            Collection<LoonElement> loonElementen = loonElementManager.getOpdrachtsElementen(opdracht);
            for (LoonElement element : loonElementen) {
                LnedefRegBv regime = element.getRegimeBv();

                Money belastbaar = element.getPropertyMoney(BELASTBAAR_KEY);
                RekenBvKey bvKey = BvTools.regimeToSingleBvKey(regime, rekenTijd.rekenDatum);
                if (!rekenTijd.isAchterstal) {
                    Money bv = element.getPropertyMoney(bvKey);
                    bvKeyToBbMap.addToMoney(bvKey, belastbaar);
                    bvKeyToBvMap.addToMoney(bvKey, bv);
                } else {
                    Money belastbaarAchterstal = element.getPropertyMoney(BELASTBAAR_ACHTERSTAL_KEY);
                    RekenBvKey bvAchterstalKey = BvTools.achterstalRegimeToSingleBvKey(regime);
                    Money bvAchterstal = element.getPropertyMoney(bvAchterstalKey);

                    bvKeyToBbAstMap.addToMoney(bvAchterstalKey, belastbaarAchterstal);
                    bvKeyToBvAstMap.addToMoney(bvAchterstalKey, bvAchterstal);
                }

            }

            Set<RekenBvKey> bvKeys = new HashSet<>(bvKeyToBvAstMap.keySet());
            bvKeys.addAll(bvKeyToBvMap.keySet());

            for (RekenBvKey bvKey : bvKeys) {
                Money belastbaar = bvKeyToBbMap.getMoney(bvKey).max(Money.ZERO);
                Money bv = bvKeyToBvMap.getMoney(bvKey);
                Money belastbaarAchterstal = bvKeyToBbAstMap.getMoney(bvKey).max(Money.ZERO);
                Money bvAchterstal = bvKeyToBvAstMap.getMoney(bvKey);

                boolean test;
                if (!rekenTijd.isAchterstal) {
                    test = belastbaar.compareTo(bv) < 0;
                } else {
                    test = belastbaarAchterstal.compareTo(bvAchterstal) < 0;
                }

                if (test) {
                    regulManager.doRegulException(opdracht, Regulkode.BV_GROTER_DAN_BELASTBAAR);
                }
            }
        }
    }

}
